```javascript
const cache = new Map();

async function getUserProfile(userId) {
  if (cache.has(userId)) {
    return cache.get(userId);
  }
  const profile = await db.query('SELECT * FROM users WHERE id = $1', [userId]);
  cache.set(userId, profile);
  return profile;
